  ('Peach Creek Berry Ranch', 'peach-creek-berry-ranch-gonzales', 'farm', '1540 CR 430', 'Gonzales', 'TX', '78629', 29.5018, -97.4523, NULL, NULL, 'Scenic ranch between San Antonio and Houston with seasonal berry fields.', '2026-01-01T00:00:00.000Z', '2026-01-01T00:00:00.000Z'),
  ('Piney Woods Blueberries', 'piney-woods-blueberries-lufkin', 'farm', '2801 S Timberland Dr', 'Lufkin', 'TX', '75901', 31.2891, -94.8501, NULL, '(936) 634-8277', 'Deep East Texas blueberry farm with multiple U-pick varieties from May to July.', '2026-01-01T00:00:00.000Z', '2026-01-01T00:00:00.000Z'),
